// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
//
// Cap/stem/collar/grass are welded with api.smoothWeld so the junctions read
// as smooth fleshy transitions instead of hard right-angle creases. Welding
// remeshes the surface and destroys the original api.label() regions, so the
// four parts are recolored afterward with geometric api.paint.* descriptors
// (z-slabs / annular cylinders) instead of paint.label. Amanita-style white
// spots are added on top of the welded cap via api.scatter + api.label
// (labels DO survive the later boolean union, unlike the weld).
const __pwModel = (() => {
const { Manifold, CrossSection, label } = api;

// --- Stem: tapered cylinder, slightly wider at base ---
// r_base=4.5, r_top=3.5, h=15, from z=1.5 to z=16.5
const stemRaw = Manifold.cylinder(15, 4.5, 3.5).translate([0, 0, 1.5]);

// --- Collar ring: thin solid disk around stem at z=14 ---
const collarRaw = Manifold.cylinder(1.5, 5.5, 5.5).translate([0, 0, 14]);

// --- Cap: squashed sphere dome ---
// Center at z=18, scale 0.75 in Z, r=12; cut below z=15 so the flat brim
// overlaps the stem top (z=16.5) by 1.5 units.
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}
const capSphere = Manifold.sphere(12).scale([1, 1, 0.75]).translate([0, 0, 18]);
const capCut = box([-15, -15, -10], [15, 15, 15]);
const capRaw = capSphere.subtract(capCut);

// --- Grass base: flat green disk ---
const grassRaw = Manifold.cylinder(2, 8, 8.5).translate([0, 0, 0]);

// --- Weld all four pieces into one smooth-jointed body ---
// Parts overlap 0.5-1.5 units at every seam (grass/stem, stem/collar,
// stem/cap), which is enough for the lattice fillet to bridge the creases.
const welded = api.smoothWeld([grassRaw, stemRaw, collarRaw, capRaw], { radius: 2.2, resolution: 176 });

// --- Amanita spots: white discs scattered on the cap top only ---
// Squashed sphere, half-thickness along the normal ~= 1.5*0.55 = 0.825, so a
// -0.35 sink leaves a proud dome bump (not fully swallowed by the surface).
const spotInstance = label(Manifold.sphere(1.5, 24).scale([1, 1, 0.55]), 'spot');
const spots = api.scatter(welded, spotInstance, {
  count: 46,
  seed: 11,
  alignToNormal: true,
  spin: false,
  scale: [0.8, 1.15],
  offset: -0.35,               // sink slightly so the base fuses with the cap surface
  minSpacing: 4.2,
  where: (p, n) => n[2] > 0.55 && p[2] > 16.5, // upper cap dome only, not the brim/stem
});

const merged = api.expectUnion([welded, spots], { expectComponents: 1 });
return merged;
})();

// --- Recolor geometrically (labels didn't survive the weld) ---
// Broad regions first, narrower/overlapping regions last so they win.
// NOTE: api.paint.slab's band is [offset, offset+thickness] (one-sided from
// offset), not centered on it.
api.paint.slab({ axis: 'z', offset: 13, thickness: 14, color: [0.85, 0.15, 0.15] });           // cap (z 13..27)
api.paint.slab({ axis: 'z', offset: -1, thickness: 4, color: [0.25, 0.65, 0.2] });              // grass base (z -1..3)
api.paint.cylinder({ center: [0, 0], rMin: 0, rMax: 5, zMin: 0, zMax: 13, color: [0.95, 0.95, 0.92] });   // stem shaft
api.paint.cylinder({ center: [0, 0], rMin: 0, rMax: 7, zMin: 13, zMax: 16.5, color: [0.95, 0.95, 0.92] }); // collar ring
api.paint.label('spot', [0.97, 0.96, 0.93]);   // Amanita spots, painted last so they stay visible on the red cap

return __pwModel;
